1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Customer {
14	  yearsWithMHPCO: number;
15	}
16	
17	interface Scenario {
18	  customer: Customer;
19	  steps: QuoteStep[];
20	}
21	
22	const BASE_PREMIUM: Record<string, number> = {
23	  sword: 100,
24	  amulet: 60,
25	  staff: 80,
26	  potion: 40,
27	  rune: 25,
28	  moonstone: 25,
29	};
30	
31	const FIRST_INSURANCE_RATE = 0.1;
32	const PROCESSING_FEE = 5;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FOLLOWUP_DISCOUNT_RATE = 0.15;
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PREMIUM = 60;
40	
41	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
42	
43	const typeBasePremium = (type: string, count: number): number =>
44	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
45	    ? COMPONENT_BLOCK_PREMIUM
46	    : count * BASE_PREMIUM[type];
47	
48	const CURSE_RATE = 0.5;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const HIGH_ENCHANTMENT_RATE = 0.3;
51	
52	const surchargeForItem = (item: Item): number => {
53	  const base = BASE_PREMIUM[item.type];
54	  const curse = item.cursed ? CURSE_RATE * base : 0;
55	  const highEnchantment =
56	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
57	      ? HIGH_ENCHANTMENT_RATE * base
58	      : 0;
59	  return curse + highEnchantment;
60	};
61	
62	const itemSurcharges = (items: Item[]): number =>
63	  items.reduce((sum, item) => sum + surchargeForItem(item), 0);
64	
65	const countByType = (items: Item[]): Map<string, number> => {
66	  const counts = new Map<string, number>();
67	  for (const item of items) {
68	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
69	  }
70	  return counts;
71	};
72	
73	const policyBasePremium = (items: Item[]): number =>
74	  [...countByType(items)].reduce(
75	    (total, [type, count]) => total + typeBasePremium(type, count),
76	    0,
77	  );
78	
79	const isLoyal = (customer: Customer): boolean =>
80	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
81	
82	const policyModifierRate = (customer: Customer, isFollowup: boolean): number =>
83	  FIRST_INSURANCE_RATE -
84	  (isLoyal(customer) ? LOYALTY_DISCOUNT_RATE : 0) -
85	  (isFollowup ? FOLLOWUP_DISCOUNT_RATE : 0);
86	
87	const quotePremium = (
88	  step: QuoteStep,
89	  customer: Customer,
90	  isFollowup: boolean,
91	): number => {
92	  const policyBase = policyBasePremium(step.items);
93	  const policyModifiers = policyBase * policyModifierRate(customer, isFollowup);
94	  return Math.ceil(
95	    policyBase + itemSurcharges(step.items) + policyModifiers + PROCESSING_FEE,
96	  );
97	};
98	
99	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
100	  return {
101	    results: scenario.steps.map((step, index) => ({
102	      premium: quotePremium(step, scenario.customer, index > 0),
103	    })),
104	  };
105	};
